#include<cstdio>
#include<algorithm>
#include<vector>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=2e5+10,INF=0x3f3f3f3f;
struct Graph
{
	int head[N],des[M],val[M],nxt[M],cnt;
	inline void ins(int x,int y,int z){nxt[++cnt]=head[x];head[x]=cnt;des[cnt]=y;val[cnt]=z;}
}a;
int R,cnt,n,QL,QR,dis[N],dep[N],ql[N],qr[N],idx[N];bool vis[N];
struct BITree
{
	int t[N],n;inline int lb(int k){return k&(-k);}
	inline void add(int pos,int val){while(pos<=QR)t[pos]+=val,pos+=lb(pos);}
	inline int qry(int pos){int res=0;while(pos)res+=t[pos],pos^=lb(pos);return res;}
	inline void Init(int NN){n=NN;}
}t;

inline int Max(int x,int y){return x>y?x:y;}
inline int Min(int x,int y){return x<y?x:y;}
vector<pair<int,int> > tmp,Q;long long ans;
inline void Getdp(int u,int Dis,int Dep=1,int fa=0)
{
	if(Dep>QR)return;tmp.push_back(make_pair(Dis,Dep));
	grep(a,u,i){int v=a.des[i];if(vis[v]||v==fa)continue;Getdp(v,Max(Dis,a.val[i]),Dep+1,u);}
}
inline void Solve(int u)
{
	Q.clear();grep(a,u,i)
	{
		int v=a.des[i];if(vis[v])continue;
		tmp.clear();Getdp(v,a.val[i]);sort(tmp.begin(),tmp.end());
		int sz=tmp.size();rep(0,sz-1,i)
		{
			int Dis=tmp[i].first,Dep=tmp[i].second;
			ans-=1ll*Dis*(t.qry(QR-Dep)-t.qry(Max(0,QL-Dep-1)));t.add(Dep,1);
		}
		rep(0,sz-1,i)t.add(tmp[i].second,-1),Q.push_back(tmp[i]);
	}
	sort(Q.begin(),Q.end());int sz=Q.size();rep(0,sz-1,i)
	{
		int Dis=Q[i].first,Dep=Q[i].second;
		ans+=1ll*Dis*(t.qry(QR-Dep)-t.qry(Max(0,QL-Dep-1)));t.add(Dep,1); 
	}
	rep(0,sz-1,i)t.add(Q[i].second,-1),ans+=(Q[i].second>=QL)*Q[i].first;
//	printf("%lld\n",ans);
}
int mx,rt,siz[N],tsz;inline void GetRt(int u,int fa=0)
{
	int son=0;siz[u]=1;grep(a,u,i)
	{
		int v=a.des[i];if(vis[v]||v==fa)continue;
		GetRt(v,u);son=Max(son,siz[v]);siz[u]+=siz[v];
	}
	son=Max(son,tsz-son);(son<mx)?mx=son,rt=u:0;
}
inline void Slide(int u)
{
//	printf("----- %d -----\n",u);
	vis[u]=1;Solve(u);grep(a,u,i)
	{
		int v=a.des[i];if(vis[v])continue;
		mx=INF;tsz=siz[v];GetRt(v);Slide(rt);
	}
}
signed main()
{
	n=read();QL=read();QR=read();t.Init(1e5);
	rep(2,n,i){int x=read(),y=read(),z=read();a.ins(x,y,z);a.ins(y,x,z);}
	tsz=n;mx=INF;GetRt(1);Slide(rt);printf("%lld\n",ans<<1);
}
